module audio_mux (
    input [15:0] audio_in1,
    input [15:0] audio_in2,
    input select,
    output reg [15:0] audio_out
);
  wire [15:0] _tap_audio_in1 = audio_in1 & {16{1'b1}};


always @(*) begin
    if (select == 0) 
        audio_out = audio_in1;
    else 
        audio_out = audio_in2;
end

endmodule
